		_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
			Kind:      noChanges.EventKind,
			Summary:   noChanges.EventKind,
			Body:      noChanges.EventBody,
			Actor:     assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
