		if err := addBeadLabel(ctx, w.Store, candidate.ID, noChanges.Label); err != nil {
			_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
				return commitOutcomeError("addBeadLabel", assignee, result, err)
