		return "operator_attention"
	case ExecuteBeadStatusLandConflict, ExecuteBeadStatusLandConflictUnresolvable, ExecuteBeadStatusLandConflictOperatorRequired:
		return "conflict"
	default:
		return "not_landed"
	}
}

